$ErrorActionPreference = "Stop"
$root = Split-Path -Parent $MyInvocation.MyCommand.Path
$web  = Join-Path $root "servicesos-web"
$mod  = Join-Path $web  "src\modules\growthAI"
New-Item -ItemType Directory -Force -Path $mod | Out-Null
Write-Host "Directory ready"
[IO.File]::WriteAllBytes((Join-Path $mod "brandProfiles.js"), [Convert]::FromBase64String(""))
Write-Host "  Wrote brandProfiles.js"
[IO.File]::WriteAllBytes((Join-Path $mod "draftStorage.js"), [Convert]::FromBase64String(""))
Write-Host "  Wrote draftStorage.js"
[IO.File]::WriteAllBytes((Join-Path $mod "growthAIService.js"), [Convert]::FromBase64String(""))
Write-Host "  Wrote growthAIService.js"
[IO.File]::WriteAllBytes((Join-Path $mod "GrowthAIPage.jsx"), [Convert]::FromBase64String(""))
Write-Host "  Wrote GrowthAIPage.jsx"
$f = Join-Path $web "src\App.jsx"
$t = [IO.File]::ReadAllText($f, [Text.Encoding]::UTF8)
$t = $t.Replace('import { saveLead }           from "./services/crmService.js";', 'import { saveLead }           from "./services/crmService.js";\nimport GrowthAIPage           from "./modules/growthAI/GrowthAIPage.jsx";')
$o2 = '    id: "ai-training",\n    icon: "🤖",\n    label: "AI training",\n    roles: ["super-admin"],\n  },\n  {\n    id: "backup",'
$n2 = '    id: "ai-training",\n    icon: "🤖",\n    label: "AI training",\n    roles: ["super-admin"],\n  },\n  {\n    id: "growth-ai",\n    icon: "🚀",\n    label: "Marketing helper",\n    roles: ["super-admin"],\n  },\n  {\n    id: "backup",'
$t = $t.Replace($o2, $n2)
$t = $t.Replace('      case "settings":          return <CompanySettings />;\n      default:', '      case "settings":          return <CompanySettings />;\n      case "growth-ai":         return <GrowthAIPage />;\n      default:')
[IO.File]::WriteAllText($f, $t, [Text.Encoding]::UTF8)
Write-Host "  Patched App.jsx"
Set-Location $root
git add servicesos-web/src/App.jsx servicesos-web/src/modules/growthAI/
git diff --cached --stat
git commit -m "Add GrowthAI Phase 0 local marketing helper"
Write-Host "Done. Run: git push origin master"
